#!/usr/bin/env node

const { spawn, exec } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

const CONFIG = {
  nodeVersion: process.env.NODE_VERSION || '18',
  environment: process.env.DEPLOY_ENV || 'production',
  deployTarget: process.env.DEPLOY_TARGET || 'server',
  skipTests: process.env.SKIP_TESTS === 'true',
  parallelJobs: parseInt(process.env.PARALLEL_JOBS || os.cpus().length),
  cacheDir: process.env.CACHE_DIR || path.join(os.tmpdir(), 'ci-cache'),
  artifactDir: process.env.ARTIFACT_DIR || './dist',
  deployServer: process.env.DEPLOY_SERVER,
  deployPath: process.env.DEPLOY_PATH || '/var/www/app',
  deployUser: process.env.DEPLOY_USER || 'deploy',
};

function runCommand(command, args = [], options = {}) {
  return new Promise((resolve, reject) => {
    const proc = spawn(command, args, {
      stdio: 'inherit',
      shell: true,
      ...options,
    });

    proc.on('close', (code) => {
      if (code !== 0) {
        reject(new Error(`Command failed: ${command} ${args.join(' ')}`));
      } else {
        resolve();
      }
    });

    proc.on('error', reject);
  });
}

function runCommandSilent(command) {
  return new Promise((resolve, reject) => {
    exec(command, (error, stdout, stderr) => {
      if (error) {
        reject(error);
      } else {
        resolve(stdout.trim());
      }
    });
  });
}

async function checkCache() {
  console.log('⚡ Checking cache...');
  
  if (!fs.existsSync(CONFIG.cacheDir)) {
    fs.mkdirSync(CONFIG.cacheDir, { recursive: true });
  }

  const packageLockPath = './package-lock.json';
  const yarnLockPath = './yarn.lock';
  const pnpmLockPath = './pnpm-lock.yaml';
  
  let lockFile = null;
  let packageManager = 'npm';
  
  if (fs.existsSync(pnpmLockPath)) {
    lockFile = pnpmLockPath;
    packageManager = 'pnpm';
  } else if (fs.existsSync(yarnLockPath)) {
    lockFile = yarnLockPath;
    packageManager = 'yarn';
  } else if (fs.existsSync(packageLockPath)) {
    lockFile = packageLockPath;
    packageManager = 'npm';
  }

  if (lockFile) {
    const lockHash = await runCommandSilent(`sha256sum ${lockFile} | cut -d' ' -f1`);
    const cacheKey = `node_modules-${lockHash}`;
    const cachePath = path.join(CONFIG.cacheDir, cacheKey);
    
    return { cacheKey, cachePath, packageManager, exists: fs.existsSync(cachePath) };
  }
  
  return { cacheKey: null, cachePath: null, packageManager, exists: false };
}

async function installDependencies() {
  console.log('📦 Installing dependencies...');
  const startTime = Date.now();

  const cache = await checkCache();
  
  if (cache.exists && cache.cachePath) {
    console.log('✓ Restoring from cache...');
    await runCommand('rm', ['-rf', 'node_modules']);
    await runCommand('cp', ['-r', cache.cachePath, 'node_modules']);
  } else {
    if (cache.packageManager === 'pnpm') {
      await runCommand('pnpm', ['install', '--frozen-lockfile', '--prefer-offline']);
    } else if (cache.packageManager === 'yarn') {
      await runCommand('yarn', ['install', '--frozen-lockfile', '--prefer-offline']);
    } else {
      await runCommand('npm', ['ci', '--prefer-offline']);
    }
    
    if (cache.cachePath) {
      await runCommand('rm', ['-rf', cache.cachePath]);
      await runCommand('cp', ['-r', 'node_modules', cache.cachePath]);
    }
  }

  const duration = ((Date.now() - startTime) / 1000).toFixed(2);
  console.log(`✓ Dependencies installed in ${duration}s`);
}

async function runTests() {
  if (CONFIG.skipTests) {
    console.log('⚠ Skipping tests...');
    return;
  }

  console.log('🧪 Running tests...');
  const startTime = Date.now();

  try {
    await runCommand('npm', ['run', 'test', '--', '--ci', '--maxWorkers=' + CONFIG.parallelJobs]);
  } catch (error) {
    console.error('✗ Tests failed');
    throw error;
  }

  const duration = ((Date.now() - startTime) / 1000).toFixed(2);
  console.log(`✓ Tests passed in ${duration}s`);
}

async function buildApplication() {
  console.log('🔨 Building application...');
  const startTime = Date.now();

  await runCommand('npm', ['run', 'build']);

  if (!fs.existsSync(CONFIG.artifactDir)) {
    throw new Error(`Build directory ${CONFIG.artifactDir} does not exist`);
  }

  const duration = ((Date.now() - startTime) / 1000).toFixed(2);
  console.log(`✓ Build completed in ${duration}s`);
}

async function createArtifact() {
  console.log('📦 Creating deployment artifact...');
  const startTime = Date.now();

  const artifactName = `artifact-${Date.now()}.tar.gz`;
  const artifactPath = path.join(os.tmpdir(), artifactName);

  const filesToInclude = [
    CONFIG.artifactDir,
    'package.json',
    'package-lock.json',
    'node_modules',
  ].filter(f => fs.existsSync(f));

  await runCommand('tar', [
    '-czf',
    artifactPath,
    ...filesToInclude,
  ]);

  const duration = ((Date.now() - startTime) / 1000).toFixed(2);
  console.log(`✓ Artifact created in ${duration}s: ${artifactPath}`);
  
  return artifactPath;
}

async function deployToServer(artifactPath) {
  console.log('🚀 Deploying to production...');
  const startTime = Date.now();

  if (!CONFIG.deployServer) {
    throw new Error('DEPLOY_SERVER environment variable not set');
  }

  const remoteArtifact = `/tmp/artifact-${Date.now()}.tar.gz`;
  const deployHost = `${CONFIG.deployUser}@${CONFIG.deployServer}`;

  console.log('  → Uploading artifact...');
  await runCommand('scp', [
    '-o', 'StrictHostKeyChecking=no',
    '-o', 'Compression=yes',
    artifactPath,
    `${deployHost}:${remoteArtifact}`,
  ]);

  console.log('  → Extracting and deploying...');
  const deployCommands = [
    `mkdir -p ${CONFIG.deployPath}`,
    `cd ${CONFIG.deployPath}`,
    `tar -xzf ${remoteArtifact}`,
    `rm ${remoteArtifact}`,
    `pm2 reload ecosystem.config.js --update-env || pm2 start ecosystem.config.js`,
  ].join(' && ');

  await runCommand('ssh', [
    '-o', 'StrictHostKeyChecking=no',
    deployHost,
    deployCommands,
  ]);

  const duration = ((Date.now() - startTime) / 1000).toFixed(2);
  console.log(`✓ Deployment completed in ${duration}s`);
}

async function deployDocker(artifactPath) {
  console.log('🐳 Deploying with Docker...');
  const startTime = Date.now();

  const imageName = process.env.DOCKER_IMAGE || 'app';
  const imageTag = process.env.DOCKER_TAG || 'latest';
  const registry = process.env.DOCKER_REGISTRY || '';

  const fullImageName = registry 
    ? `${registry}/${imageName}:${imageTag}`
    : `${imageName}:${imageTag}`;

  console.log('  → Building Docker image...');
  await runCommand('docker', ['build', '-t', fullImageName, '.']);

  if (registry) {
    console.log('  → Pushing to registry...');
    await runCommand('docker', ['push', fullImageName]);
  }

  if (CONFIG.deployServer) {
    console.log('  → Deploying to remote server...');
    const deployHost = `${CONFIG.deployUser}@${CONFIG.deployServer}`;
    
    const deployCommands = [
      registry ? `docker pull ${fullImageName}` : '',
      `docker stop ${imageName} || true`,
      `docker rm ${imageName} || true`,
      `docker run -d --name ${imageName} --restart unless-stopped -p 3000:3000 ${fullImageName}`,
    ].filter(Boolean).join(' && ');

    await runCommand('ssh', [
      '-o', 'StrictHostKeyChecking=no',
      deployHost,
      deployCommands,
    ]);
  }

  const duration = ((Date.now() - startTime) / 1000).toFixed(2);
  console.log(`✓ Docker deployment completed in ${duration}s`);
}

async function healthCheck() {
  console.log('🏥 Running health check...');
  
  const healthUrl = process.env.HEALTH_CHECK_URL;
  if (!healthUrl) {
    console.log('  ⚠ No health check URL configured, skipping...');
    return;
  }

  const maxRetries = 30;
  const retryDelay = 2000;

  for (let i = 0; i < maxRetries; i++) {
    try {
      const response = await fetch(healthUrl, { timeout: 5000 });
      if (response.ok) {
        console.log('✓ Health check passed');
        return;
      }
    } catch (error) {
      if (i < maxRetries - 1) {
        await new Promise(resolve => setTimeout(resolve, retryDelay));
      }
    }
  }

  throw new Error('Health check failed');
}

async function cleanup(artifactPath) {
  console.log('🧹 Cleaning up...');
  
  if (artifactPath && fs.existsSync(artifactPath)) {
    fs.unlinkSync(artifactPath);
  }

  const cacheMaxAge = 7 * 24 * 60 * 60 * 1000;
  if (fs.existsSync(CONFIG.cacheDir)) {
    const cacheFiles = fs.readdirSync(CONFIG.cacheDir);
    const now = Date.now();
    
    for (const file of cacheFiles) {
      const filePath = path.join(CONFIG.cacheDir, file);
      const stats = fs.statSync(filePath);
      
      if (now - stats.mtimeMs > cacheMaxAge) {
        fs.rmSync(filePath, { recursive: true, force: true });
      }
    }
  }
}

async function main() {
  const totalStartTime = Date.now();
  let artifactPath = null;

  console.log('🚀 Starting CI/CD Pipeline');
  console.log(`Environment: ${CONFIG.environment}`);
  console.log(`Deploy Target: ${CONFIG.deployTarget}`);
  console.log('');

  try {
    await installDependencies();
    await runTests();
    await buildApplication();
    
    artifactPath = await createArtifact();

    if (CONFIG.deployTarget === 'docker') {
      await deployDocker(artifactPath);
    } else {
      await deployToServer(artifactPath);
    }

    await healthCheck();
    await cleanup(artifactPath);

    const totalDuration = ((Date.now() - totalStartTime) / 1000).toFixed(2);
    console.log('');
    console.log(`✓ Pipeline completed successfully in ${totalDuration}s`);
    process.exit(0);
  } catch (error) {
    console.error('');
    console.error('✗ Pipeline failed:', error.message);
    
    await cleanup(artifactPath);
    
    process.exit(1);
  }
}

main();